/**
 * Typed shim for the bundled city database.
 *
 * The generated `cities.min.json` is a ~24k-element array; declaring its type
 * here (instead of letting `resolveJsonModule` infer the literal) keeps
 * type-checking fast and gives the import a precise `CityRow[]` type.
 */
import type { CityRow } from '../lib/geo/cityLookup';

declare const cities: CityRow[];
export default cities;
